import React, { useEffect, useState } from "react";
import { Form, Col, Button } from "react-bootstrap";
import { Link, useParams } from "react-router-dom";
import { readCard } from "../../utils/api/index.js";

function EditCard() {
    const [card, setCard] = useState();
    const params = useParams();

    useEffect(() => {
        async function loadCard() {
            const cardData = readCard(params.cardId);
            setCard(cardData);
        }
        loadCard();
    }, [])

    function handleEditCardBtn() {

    }

  if (!card) return <p>Loading...</p>;
  return (
    <div>
      <Form>
        <Col>
          <h1>Edit Card</h1>
          <Form.Label className="mt-1">Front</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Frontside of card"
            as="textarea"
            id="front"
          ></Form.Control>
          <Form.Label className="mt-1">Back</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Backside of card"
            as="textarea"
            id="back"
          ></Form.Control>
          <Link to={`/decks/${params.deckId}`}>
            <Button className="mt-2 mr-1" variant="secondary">
              Cancel
            </Button>
          </Link>
          <Button onClick={() => handleEditCardBtn()} className="mt-2 mr-1">
            Submit
          </Button>
        </Col>
      </Form>
    </div>
  );
}

export default EditCard;
